def current_user(db):
    uid = st.session_state.get("usuario_id")
    if not uid:
        return None
    try:
        u = db.get(Usuario, int(uid))
        if not u or not u.ativo:
            return None
        return u
    except Exception:
        return None

def user_selector(db, location="sidebar"):
    return current_user(db)

def logout_user():
    for k in ["auth_ok", "usuario_id", "usuario_nome", "modulo", "page_nr12", "page_ehs", "page_energia", "page_nearmiss", "page_legal", "page_relatorios"]:
        if k in st.session_state:
            del st.session_state[k]

